import {
  isFinalProcessingLevel,
  isVoucherDocumentTerminalLocked,
  VOUCHER_FINAL_PROCESSING_LEVEL,
} from './voucherProcessingLevelDisplay';

/** Kỳ kế toán — subset dùng gate toolbar (load từ `GET /accounting/periods`). */
export interface AccountingPeriodGate {
  year: number;
  month: number;
  status: 'Open' | 'Closed' | 'Locked' | string;
}

/**
 * Ẩn nút Sửa/Xóa — chỉ hiện khi chứng từ còn sửa/xóa được (Draft, chưa khóa form).
 * Rule: `voucher-form-toolbar.md` § Ẩn Sửa / Xóa.
 */
export function canShowVoucherEditDelete(
  status: string,
  processingLevel: string,
  isNew: boolean,
): boolean {
  if (isNew) return false;
  if (status !== 'Draft') return false;
  if (isVoucherDocumentTerminalLocked(status)) return false;
  return true;
}

export function isAccountingPeriodLockedForDate(
  voucherDate: string,
  periods: AccountingPeriodGate[],
): boolean {
  if (!voucherDate?.trim() || periods.length === 0) return false;
  const d = voucherDate.trim().slice(0, 10);
  const [y, m] = d.split('-').map(Number);
  if (!y || !m) return false;
  const period = periods.find(p => p.year === y && p.month === m);
  return period?.status === 'Locked';
}

/**
 * Phê duyệt — chuyển mức xử lý (tăng/giảm/bỏ hoạch toán).
 * Rule: `voucher-form-toolbar.md` § Phê duyệt + khóa sổ.
 */
export function canVoucherApprove(input: {
  isNew: boolean;
  status: string;
  processingLevel: string;
  voucherDate: string;
  periods: AccountingPeriodGate[];
  targetLevel?: string;
}): boolean {
  if (input.isNew) return false;
  if (input.status === 'Cancelled') return false;

  const current = String(input.processingLevel ?? '').trim();
  const target = String(input.targetLevel ?? current).trim();
  const downgrading =
    target !== current &&
    (Number(target) < Number(current) ||
      (isFinalProcessingLevel(current) && !isFinalProcessingLevel(target)));

  const unposting =
    downgrading &&
    (isFinalProcessingLevel(current) || input.status === 'Posted');

  if (unposting && isAccountingPeriodLockedForDate(input.voucherDate, input.periods)) {
    return false;
  }

  return true;
}

/** Tooltip khi Phê duyệt disabled — bỏ hoạch toán trong kỳ Locked. */
export function voucherApproveDisabledReason(input: {
  isNew: boolean;
  status: string;
  processingLevel: string;
  voucherDate: string;
  periods: AccountingPeriodGate[];
}): string | undefined {
  if (input.isNew) return 'Lưu chứng từ trước khi phê duyệt';
  if (input.status === 'Cancelled') return 'Chứng từ đã hủy';
  if (
    isFinalProcessingLevel(input.processingLevel) ||
    input.status === 'Posted'
  ) {
    if (isAccountingPeriodLockedForDate(input.voucherDate, input.periods)) {
      return 'Kỳ kế toán đã khóa sổ — không thể bỏ hoạch toán hoặc hạ mức xử lý';
    }
  }
  return undefined;
}

export { VOUCHER_FINAL_PROCESSING_LEVEL };
