import React, { useEffect, useRef } from 'react';
import { Input, MoneyInput } from '@linm-soft/common-components';
import { CustomerSearchField, AccountSearchInput } from '../../../../../components/search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import { formatMoneyVnd } from '../../../../../utils/formatters';
import type { CashVoucherFormViewModel } from '../hooks/useCashVoucherFormController';
import styles from '../../../../../styles/documentForm.module.css';

/** Clicks/keys on lookup inputs must not move focus to `<tr>` — breaks SearchInput dropdown. */
function isLineRowFieldTarget(target: HTMLElement): boolean {
  return !!target.closest(
    'input, textarea, select, button, a, [role="option"], [role="listbox"]',
  );
}

export const CashVoucherLinesSection: React.FC<{ vm: CashVoucherFormViewModel }> = ({ vm }) => {
  const {
    labels,
    tid,
    viewSectionClass,
    showLineCustomer,
    showInvoiceGrid,
    isReadOnly,
    formState,
    lines,
    searchFieldClass,
    searchDisabled,
    ph,
    fieldLockProps,
    staticFieldProps,
    handleUpdateLine,
    resolveInvoiceForLine,
    fieldErrors,
    lineAccountSearchClass,
    handleRemoveLine,
    handleAddLine,
    handleCopyLine,
    handleSelectLine,
    selectedLineIndex,
    highlightLineId,
  } = vm;

  const sectionRef = useRef<HTMLDivElement>(null);
  const rowRefs = useRef<(HTMLTableRowElement | null)[]>([]);

  useEffect(() => {
    const row = rowRefs.current[selectedLineIndex];
    const active = document.activeElement as HTMLElement | null;
    if (active && isLineRowFieldTarget(active) && sectionRef.current?.contains(active)) {
      row?.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
      return;
    }
    row?.focus({ preventScroll: true });
    row?.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
  }, [selectedLineIndex]);

  useEffect(() => {
    const root = sectionRef.current;
    if (!root) return undefined;

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key !== 'ArrowUp' && e.key !== 'ArrowDown') return;
      const target = e.target as HTMLElement;
      if (isLineRowFieldTarget(target)) return;
      if (!root.contains(target)) return;

      e.preventDefault();
      if (e.key === 'ArrowDown') {
        handleSelectLine(Math.min(selectedLineIndex + 1, lines.length - 1));
      } else {
        handleSelectLine(Math.max(selectedLineIndex - 1, 0));
      }
    };

    root.addEventListener('keydown', onKeyDown);
    return () => root.removeEventListener('keydown', onKeyDown);
  }, [handleSelectLine, lines.length, selectedLineIndex]);

  const focusRow = (idx: number) => {
    rowRefs.current[idx]?.focus({ preventScroll: true });
  };

  return (
    <div
      ref={sectionRef}
      className={[styles.section, viewSectionClass].filter(Boolean).join(' ')}
      id={tid('section-lines')}
      data-testid={tid('section-lines')}
    >
      <h2 className={styles.sectionTitle}>{labels.sectionLines}</h2>
      <div className={styles.tableWrapper}>
        <table className={[styles.linesTable, styles.linesTableStacked].join(' ')}>
          <thead>
            <tr>
              {showLineCustomer && <th>{labels.lineCustomer}</th>}
              {showInvoiceGrid ? (
                <>
                  <th>{labels.invoiceCode}</th>
                  <th>{labels.invoiceDate}</th>
                  <th>{labels.invoiceTotal}</th>
                  <th>{labels.invoicePaid}</th>
                  <th>{labels.invoiceRemaining}</th>
                  <th className={styles.thAmount}>{labels.lineAmount}</th>
                  <th className={styles.thDesc}>{labels.lineDesc}</th>
                </>
              ) : (
                <>
                  <th className={styles.thAccount}>{labels.lineThAccount}</th>
                  <th className={styles.thAmount}>{labels.lineAmount}</th>
                  <th className={styles.thCostCenter}>{labels.costCenter}</th>
                  <th className={styles.thDesc}>{labels.lineDesc}</th>
                </>
              )}
              {!isReadOnly && <th className={styles.thDel} />}
            </tr>
          </thead>
          <tbody>
            {formState.lineRows.map((lineState, idx) => {
              const line = lines[idx];
              const isSelected = selectedLineIndex === idx;
              const isHighlight = highlightLineId === lineState.lineId;
              const rowClass = [
                isSelected ? styles.lineRowSelected : '',
                isHighlight ? styles.lineRowHighlight : '',
                isHighlight ? styles.lineRowEnter : '',
              ].filter(Boolean).join(' ');

              return (
                <tr
                  key={lineState.lineId}
                  ref={el => { rowRefs.current[idx] = el; }}
                  className={[styles.lineRow, rowClass].filter(Boolean).join(' ')}
                  data-testid={tid(`line-${idx}`)}
                  tabIndex={isSelected ? 0 : -1}
                  aria-selected={isSelected}
                  onClick={e => {
                    handleSelectLine(idx);
                    const target = e.target as HTMLElement;
                    if (isLineRowFieldTarget(target)) return;
                    focusRow(idx);
                  }}
                  onKeyDown={e => {
                    if (e.key !== 'ArrowUp' && e.key !== 'ArrowDown') return;
                    const target = e.target as HTMLElement;
                    if (isLineRowFieldTarget(target)) return;
                    e.preventDefault();
                    if (e.key === 'ArrowDown' && idx < lines.length - 1) {
                      handleSelectLine(idx + 1);
                    } else if (e.key === 'ArrowUp' && idx > 0) {
                      handleSelectLine(idx - 1);
                    }
                  }}
                >
                  {showLineCustomer && (
                    <td data-testid={tid(`line-${idx}-customer`)}>
                      <CustomerSearchField
                        testIdPrefix={tid(`line-${idx}-customer`)}
                        className={searchFieldClass}
                        customerId={line.customerId}
                        customerCode={line.customerCode}
                        customerName={line.customerName}
                        onSelect={c => handleUpdateLine(idx, {
                          customerId: c.customerId,
                          customerCode: c.code,
                          customerName: c.name,
                        })}
                        onClear={() => handleUpdateLine(idx, {
                          customerId: '',
                          customerCode: '',
                          customerName: '',
                        })}
                        placeholder={ph('Đối tượng...')}
                        disabled={searchDisabled}
                      />
                    </td>
                  )}
                  {showInvoiceGrid ? (
                    <>
                      <td data-testid={tid(`line-${idx}-invoiceCode`)}>
                        <Input
                          value={line.invoiceCode}
                          onChange={e => handleUpdateLine(idx, { invoiceCode: e.target.value })}
                          onBlur={e => { void resolveInvoiceForLine(idx, e.target.value); }}
                          placeholder={ph('Số HĐ...')}
                          {...fieldLockProps}
                        />
                      </td>
                      <td data-testid={tid(`line-${idx}-invoiceDate`)}>
                        <Input value={line.invoiceDate} {...staticFieldProps} />
                      </td>
                      <td data-testid={tid(`line-${idx}-invoiceTotal`)}>
                        <Input value={formatMoneyVnd(line.invoiceTotalAmount)} {...staticFieldProps} />
                      </td>
                      <td data-testid={tid(`line-${idx}-invoicePaid`)}>
                        <Input value={formatMoneyVnd(line.invoicePaidAmount)} {...staticFieldProps} />
                      </td>
                      <td data-testid={tid(`line-${idx}-invoiceRemaining`)}>
                        <Input value={formatMoneyVnd(line.invoiceRemainingAmount)} {...staticFieldProps} />
                      </td>
                      <td id={tid(`line-${idx}-amount`)} data-testid={tid(`line-${idx}-amount`)}>
                        <MoneyInput
                          value={Number(line.debitAmount)}
                          error={fieldErrors.lines?.[idx]?.debitAmount}
                          onChange={amount => handleUpdateLine(idx, { debitAmount: amount })}
                          {...fieldLockProps}
                        />
                      </td>
                      <td>
                        <Input
                          value={line.description}
                          onChange={e => handleUpdateLine(idx, { description: e.target.value })}
                          placeholder={ph('Nội dung...')}
                          {...fieldLockProps}
                        />
                      </td>
                    </>
                  ) : (
                    <>
                      <td
                        id={tid(`line-${idx}-account`)}
                        data-testid={tid(`line-${idx}-account`)}
                        data-label={labels.lineThAccount}
                      >
                        <AccountSearchInput
                          api={erpFinanceAccountSearchApi}
                          className={lineAccountSearchClass}
                          value={line.accountCode}
                          primaryDisplay={formatAccountDisplay(line.accountCode, line.accountName)}
                          error={fieldErrors.lines?.[idx]?.accountCode}
                          onChange={a => handleUpdateLine(idx, { accountCode: a.code, accountName: a.name })}
                          onClear={() => handleUpdateLine(idx, { accountCode: '', accountName: '' })}
                          placeholder={ph('TK')}
                          showSecondaryInput={false}
                          disabled={searchDisabled}
                        />
                      </td>
                      <td
                        id={tid(`line-${idx}-amount`)}
                        data-testid={tid(`line-${idx}-amount`)}
                        data-label={labels.lineAmount}
                      >
                        <MoneyInput
                          value={Number(line.debitAmount)}
                          error={fieldErrors.lines?.[idx]?.debitAmount}
                          onChange={amount => handleUpdateLine(idx, { debitAmount: amount })}
                          {...fieldLockProps}
                        />
                      </td>
                      <td data-testid={tid(`line-${idx}-costCenter`)} data-label={labels.costCenter}>
                        <Input
                          value={line.costCenterCode}
                          onChange={e => handleUpdateLine(idx, { costCenterCode: e.target.value })}
                          placeholder={ph('Mã VV...')}
                          {...fieldLockProps}
                        />
                      </td>
                      <td data-label={labels.lineDesc}>
                        <Input
                          value={line.description}
                          onChange={e => handleUpdateLine(idx, { description: e.target.value })}
                          placeholder={ph('Nội dung...')}
                          {...fieldLockProps}
                        />
                      </td>
                    </>
                  )}
                  {!isReadOnly && (
                    <td className={styles.tdDel}>
                      <button
                        type="button"
                        className={styles.btnDeleteLine}
                        onClick={e => {
                          e.stopPropagation();
                          handleRemoveLine(idx);
                        }}
                        title="Xóa dòng"
                        data-testid={tid(`line-${idx}-delete`)}
                      >
                        <i className="fas fa-trash-alt" aria-hidden="true" />
                      </button>
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {!isReadOnly && (
        <div className={styles.linesActions}>
          <button
            type="button"
            className={styles.btnAddLine}
            data-testid={tid('add-line-btn')}
            onClick={handleAddLine}
          >
            {labels.addLine}
          </button>
          <button
            type="button"
            className={styles.btnCopyLine}
            data-testid={tid('copy-line-btn')}
            onClick={handleCopyLine}
            disabled={lines.length === 0}
          >
            {labels.copyLine}
          </button>
        </div>
      )}
    </div>
  );
};
